--
-- Table structure for table `members`
--

DROP TABLE IF EXISTS `members`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `members` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `userId` bigint(20) unsigned NOT NULL,
  `nomorAnggota` varchar(255) NOT NULL,
  `name` varchar(255) NOT NULL,
  `email` varchar(255) NOT NULL,
  `phone` varchar(255) DEFAULT NULL,
  `address` text DEFAULT NULL,
  `gender` enum('MALE','FEMALE') NOT NULL,
  `unitKerja` varchar(255) NOT NULL,
  `joinDate` timestamp NOT NULL DEFAULT current_timestamp(),
  `status` enum('ACTIVE','INACTIVE','SUSPENDED') NOT NULL DEFAULT 'ACTIVE',
  `isMemberKoperasi` tinyint(1) NOT NULL DEFAULT 1,
  `simpananPokok` decimal(15,2) NOT NULL DEFAULT 0.00,
  `simpananWajib` decimal(15,2) NOT NULL DEFAULT 0.00,
  `simpananSukarela` decimal(15,2) NOT NULL DEFAULT 0.00,
  `monthly_wajib_amount` decimal(15,2) NOT NULL DEFAULT 50000.00,
  `last_wajib_debit_date` date DEFAULT NULL,
  `points` int(11) NOT NULL DEFAULT 0,
  `tier` enum('BRONZE','SILVER','GOLD','PLATINUM') NOT NULL DEFAULT 'BRONZE',
  `totalSpent` decimal(15,2) NOT NULL DEFAULT 0.00,
  `lastPurchase` timestamp NULL DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `members_userid_unique` (`userId`),
  UNIQUE KEY `members_nomoranggota_unique` (`nomorAnggota`),
  UNIQUE KEY `members_email_unique` (`email`),
  KEY `members_status_joindate_index` (`status`,`joinDate`),
  KEY `members_nomoranggota_index` (`nomorAnggota`),
  KEY `members_tier_index` (`tier`),
  KEY `members_unitkerja_index` (`unitKerja`),
  CONSTRAINT `members_userid_foreign` FOREIGN KEY (`userId`) REFERENCES `users` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=504 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

