--
-- Table structure for table `simpanan_transactions`
--

DROP TABLE IF EXISTS `simpanan_transactions`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `simpanan_transactions` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `memberId` bigint(20) unsigned NOT NULL,
  `type` enum('POKOK','WAJIB','SUKARELA') NOT NULL,
  `transactionType` enum('SETOR','TARIK') NOT NULL,
  `amount` decimal(15,2) NOT NULL,
  `balanceAfter` decimal(15,2) NOT NULL,
  `notes` text DEFAULT NULL,
  `buktiPath` varchar(255) DEFAULT NULL,
  `processedBy` bigint(20) unsigned NOT NULL,
  `status` enum('PENDING','APPROVED','REJECTED') NOT NULL DEFAULT 'APPROVED',
  `approvedBy` bigint(20) unsigned DEFAULT NULL,
  `approvedAt` timestamp NULL DEFAULT NULL,
  `rejectionReason` text DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `simpanan_transactions_processedby_foreign` (`processedBy`),
  KEY `simpanan_transactions_approvedby_foreign` (`approvedBy`),
  KEY `simpanan_transactions_memberid_type_index` (`memberId`,`type`),
  KEY `simpanan_transactions_memberid_created_at_index` (`memberId`,`created_at`),
  KEY `simpanan_transactions_status_index` (`status`),
  CONSTRAINT `simpanan_transactions_approvedby_foreign` FOREIGN KEY (`approvedBy`) REFERENCES `users` (`id`),
  CONSTRAINT `simpanan_transactions_memberid_foreign` FOREIGN KEY (`memberId`) REFERENCES `members` (`id`) ON DELETE CASCADE,
  CONSTRAINT `simpanan_transactions_processedby_foreign` FOREIGN KEY (`processedBy`) REFERENCES `users` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=16115 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

